/**
 * ReconcilePage — post-lock outcome recording and scope-change review.
 * Route: /weekly/reconcile/:planId?
 */
import { useState, useCallback, useMemo, useEffect } from "react";
import { useParams } from "react-router-dom";
import { Check, Lock, Sparkles, Bot } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Badge } from "../components/ui/Badge.js";
import { Card, CardHeader, CardContent } from "../components/ui/Card.js";
import { Dialog, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "../components/ui/Dialog.js";
import { cn } from "../lib/utils.js";
import { usePlanApi, useCurrentPlan } from "../api/planHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { useQuery } from "../api/hooks.js";
import { useAutoReconcileAssist } from "../api/aiHooks.js";
import { useHostBridge } from "../host/HostProvider.js";
import { useAiMode } from "../lib/useAiMode.js";
import type { ReconciliationViewResponse, ReconcileCommitView, CommitOutcome, ChessPiece, CarryForwardReason } from "../api/planTypes.js";
import type { RcdoTreeNode } from "../api/rcdoTypes.js";
import { OutcomeSelector } from "../components/reconcile/OutcomeSelector.js";
import { CarryForwardDialog } from "../components/reconcile/CarryForwardDialog.js";
import { ScopeChangeTimeline } from "../components/lock/ScopeChangeTimeline.js";
import { AiSuggestedBadge } from "../components/ai/AiSuggestedBadge.js";
import { AiFeedbackButtons } from "../components/ai/AiFeedbackButtons.js";

const CHESS_PIECE_ICONS: Record<ChessPiece, string> = { KING: "♔", QUEEN: "♕", ROOK: "♖", BISHOP: "♗", KNIGHT: "♘", PAWN: "♙" };

const NOTES_REQUIRED: Set<CommitOutcome> = new Set(["PARTIALLY_ACHIEVED", "NOT_ACHIEVED", "CANCELED"]);
const CARRY_FORWARD_ELIGIBLE: Set<CommitOutcome> = new Set(["NOT_ACHIEVED", "PARTIALLY_ACHIEVED"]);

/** Build a flat map of RCDO node ID → "Rally Cry > DO > Outcome" labels. */
function buildRcdoLabels(nodes: RcdoTreeNode[] | undefined): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(ns: RcdoTreeNode[], path: string[] = []) {
    for (const n of ns) {
      const next = [...path, n.title];
      map[n.id] = next.join(" > ");
      traverse(n.children, next);
    }
  }
  traverse(nodes ?? []);
  return map;
}

function useReconcileView(planId: string | undefined) {
  const api = usePlanApi();
  return useQuery<ReconciliationViewResponse>(`reconcile-${planId ?? "none"}`, () => {
    if (!planId) return Promise.reject(new Error("No plan ID"));
    return api.getReconciliationView(planId);
  });
}

// ── BaselineColumn ────────────────────────────────────────────────────────────

function BaselineColumn({ commitView, rcdoLabels }: { readonly commitView: ReconcileCommitView; readonly rcdoLabels: Record<string, string> }) {
  const baseline = commitView.baselineSnapshot;

  if (commitView.addedPostLock) {
    return (
      <div data-testid={`baseline-col-${commitView.commitId}`} className="px-2.5 py-2 rounded-sm bg-neutral-50 text-xs text-muted italic">
        Added post-lock — no baseline
      </div>
    );
  }
  if (!baseline) {
    return <div data-testid={`baseline-col-${commitView.commitId}`} className="text-xs text-muted italic">Baseline not available</div>;
  }

  const baselineChessPiece = baseline.chessPiece as ChessPiece | null;
  const baselineTitle = baseline.title as string | null;
  const baselineEstimate = baseline.estimatePoints as number | null;
  const baselineRcdo = baseline.rcdoNodeId as string | null;
  const titleChanged = baselineTitle != null && baselineTitle !== commitView.currentTitle;
  const pieceChanged = baselineChessPiece != null && baselineChessPiece !== commitView.currentChessPiece;
  const estimateChanged = baselineEstimate != null && baselineEstimate !== commitView.currentEstimatePoints;

  return (
    <div data-testid={`baseline-col-${commitView.commitId}`} className="flex flex-col gap-1.5">
      <div data-testid={`baseline-title-${commitView.commitId}`} className={cn("text-sm font-semibold rounded-sm", titleChanged ? "bg-neutral-200 text-foreground line-through px-1 py-px" : "text-foreground")}>
        {baselineTitle ?? "—"}
      </div>
      {baselineChessPiece && (
        <div data-testid={`baseline-piece-${commitView.commitId}`} className={cn("text-xs rounded-sm", pieceChanged ? "bg-neutral-200 text-foreground line-through px-1 py-px" : "text-muted")}>
          {CHESS_PIECE_ICONS[baselineChessPiece]} {baselineChessPiece}
        </div>
      )}
      {baselineEstimate != null && (
        <div data-testid={`baseline-estimate-${commitView.commitId}`} className={cn("text-xs rounded-sm", estimateChanged ? "bg-neutral-200 text-foreground line-through px-1 py-px" : "text-muted")}>
          {baselineEstimate} pts
        </div>
      )}
      {baselineRcdo && (
        <div data-testid={`baseline-rcdo-${commitView.commitId}`} className="text-[0.7rem] text-muted">
          {rcdoLabels[baselineRcdo] ?? baselineRcdo.slice(0, 8) + "…"}
        </div>
      )}
    </div>
  );
}

// ── CurrentColumn ─────────────────────────────────────────────────────────────

function CurrentColumn({ commitView }: { readonly commitView: ReconcileCommitView }) {
  const baseline = commitView.baselineSnapshot;
  const titleChanged = baseline?.title != null && baseline.title !== commitView.currentTitle;
  const pieceChanged = baseline?.chessPiece != null && baseline.chessPiece !== commitView.currentChessPiece;
  const estimateChanged = baseline?.estimatePoints != null && baseline.estimatePoints !== commitView.currentEstimatePoints;

  return (
    <div data-testid={`current-col-${commitView.commitId}`} className="flex flex-col gap-1.5">
      <div data-testid={`current-title-${commitView.commitId}`} className={cn("text-sm font-semibold rounded-sm", titleChanged ? "bg-foreground/5 text-foreground font-bold px-1 py-px" : "text-foreground")}>
        {commitView.currentTitle}
      </div>
      <div data-testid={`current-piece-${commitView.commitId}`} className={cn("text-xs rounded-sm", pieceChanged ? "bg-foreground/5 text-foreground font-bold px-1 py-px" : "text-muted")}>
        {CHESS_PIECE_ICONS[commitView.currentChessPiece]} {commitView.currentChessPiece}
      </div>
      {commitView.currentEstimatePoints != null && (
        <div data-testid={`current-estimate-${commitView.commitId}`} className={cn("text-xs rounded-sm", estimateChanged ? "bg-foreground/5 text-foreground font-bold px-1 py-px" : "text-muted")}>
          {commitView.currentEstimatePoints} pts
        </div>
      )}
      {commitView.linkedTicketStatus && (
        <span data-testid={`ticket-status-${commitView.commitId}`} className={cn("inline-flex items-center gap-1 px-2 py-px rounded-full text-[0.7rem] font-semibold", commitView.linkedTicketStatus === "DONE" ? "bg-foreground/10 text-foreground" : "bg-neutral-200 text-neutral-700")}>
          🎫 {commitView.linkedTicketStatus}
        </span>
      )}
    </div>
  );
}

// ── ReconcileCommitRow ────────────────────────────────────────────────────────

interface ReconcileCommitRowProps {
  readonly commitView: ReconcileCommitView;
  readonly outcome: CommitOutcome | null;
  readonly notes: string;
  readonly carryForward: boolean;
  readonly notesError: string | null;
  readonly isReadOnly: boolean;
  readonly rcdoLabels: Record<string, string>;
  /** The AI-suggested outcome for this commit (ghost/preview state). */
  readonly aiSuggestedOutcome?: CommitOutcome | undefined;
  /** AI-suggested note shown as placeholder text (not pre-filled). */
  readonly aiSuggestedNote?: string | undefined;
  readonly onOutcomeChange: (outcome: CommitOutcome) => void;
  readonly onNotesChange: (notes: string) => void;
  readonly onCarryForwardChange: (checked: boolean) => void;
}

function ReconcileCommitRow({ commitView, outcome, notes, carryForward, notesError, isReadOnly, rcdoLabels, aiSuggestedOutcome, aiSuggestedNote, onOutcomeChange, onNotesChange, onCarryForwardChange }: ReconcileCommitRowProps) {
  // Ghost state: AI has a suggestion but user hasn't confirmed yet
  const isGhostState = !isReadOnly && !outcome && aiSuggestedOutcome != null;
  const needsNotes = outcome != null && NOTES_REQUIRED.has(outcome);
  const canCarryForward = !isReadOnly && outcome != null && CARRY_FORWARD_ELIGIBLE.has(outcome);
  const isAutoAchieved = commitView.linkedTicketStatus === "DONE" && outcome === "ACHIEVED" && commitView.currentOutcome === "ACHIEVED";

  return (
    <div data-testid={`reconcile-commit-row-${commitView.commitId}`} className="rounded-default border border-border bg-surface overflow-hidden">
      {/* Row header */}
      <div className="px-3 py-2.5 bg-background border-b border-border flex items-center gap-2 flex-wrap">
        <span className="font-semibold text-sm flex-1">
          {CHESS_PIECE_ICONS[commitView.currentChessPiece]} {commitView.currentTitle}
        </span>
        {commitView.addedPostLock && <Badge data-testid={`added-post-lock-badge-${commitView.commitId}`} variant="success">+ Post-lock</Badge>}
        {commitView.removedPostLock && <Badge data-testid={`removed-post-lock-badge-${commitView.commitId}`} variant="danger">− Removed</Badge>}
        {isAutoAchieved && <Badge data-testid={`auto-achieved-badge-${commitView.commitId}`} variant="success">Auto-achieved (ticket Done)</Badge>}
      </div>

      {/* Baseline vs current */}
      <div className="grid border-b border-border" style={{ gridTemplateColumns: "1fr 1fr" }}>
        <div className="px-3 py-2.5 border-r border-border">
          <p className="m-0 mb-1.5 text-[0.65rem] font-semibold uppercase tracking-wider text-muted">Baseline (at lock)</p>
          <BaselineColumn commitView={commitView} rcdoLabels={rcdoLabels} />
        </div>
        <div className="px-3 py-2.5">
          <p className="m-0 mb-1.5 text-[0.65rem] font-semibold uppercase tracking-wider text-muted">Current</p>
          <CurrentColumn commitView={commitView} />
        </div>
      </div>

      {/* Ghost/preview state: AI has a suggestion not yet confirmed */}
      {isGhostState && (
        <div
          className="px-3 py-2.5 border-b border-border bg-info-bg/60"
          data-testid={`ai-ghost-outcome-${commitView.commitId}`}
        >
          <div className="flex items-center gap-2 mb-1.5">
            <AiSuggestedBadge data-testid={`ai-suggested-badge-${commitView.commitId}`} />
            <span className="text-xs text-info">AI suggestion — click to accept:</span>
          </div>
          <button
            type="button"
            onClick={() => onOutcomeChange(aiSuggestedOutcome!)}
            className="w-full rounded-sm border border-info-border bg-info-bg px-3 py-1.5 text-xs text-info font-semibold opacity-80 hover:opacity-100 transition-opacity text-left"
            data-testid={`ai-ghost-accept-${commitView.commitId}`}
          >
            {aiSuggestedOutcome}
          </button>
        </div>
      )}

      {/* Outcome selector — shown always (user can pick any outcome) */}
      <div className={cn("px-3 py-2.5", (needsNotes || canCarryForward) && "border-b border-border")}>
        <div className="flex items-center gap-2 flex-wrap">
          <OutcomeSelector commitId={commitView.commitId} value={outcome} onChange={onOutcomeChange} disabled={isReadOnly} />
          {!isGhostState && outcome != null && aiSuggestedOutcome != null && (
            <AiSuggestedBadge data-testid={`ai-suggested-badge-${commitView.commitId}`} />
          )}
        </div>
      </div>

      {/* Notes textarea */}
      {needsNotes && (
        <div className={cn("px-3 py-2.5 flex flex-col gap-1.5", canCarryForward && "border-b border-border")}>
          <label htmlFor={`outcome-notes-${commitView.commitId}`} className="text-xs font-semibold">
            Outcome notes <span aria-hidden="true" className="text-danger">*</span>
          </label>
          <textarea
            id={`outcome-notes-${commitView.commitId}`}
            value={notes}
            onChange={(e) => onNotesChange(e.target.value)}
            rows={2}
            disabled={isReadOnly}
            data-testid={`outcome-notes-${commitView.commitId}`}
            aria-required="true"
            aria-describedby={notesError ? `notes-error-${commitView.commitId}` : undefined}
            className={cn("w-full rounded-default border bg-surface px-3 py-1.5 text-sm resize-y focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50", notesError ? "border-danger" : "border-border")}
            placeholder={aiSuggestedNote ?? "Explain what happened…"}
          />
          {notesError && <span id={`notes-error-${commitView.commitId}`} role="alert" className="text-xs text-danger">{notesError}</span>}
        </div>
      )}

      {/* Carry-forward checkbox */}
      {canCarryForward && (
        <div className="px-3 py-2.5">
          <label data-testid={`carry-forward-checkbox-label-${commitView.commitId}`} className="flex items-center gap-2 cursor-pointer text-sm">
            <input type="checkbox" checked={carryForward} onChange={(e) => onCarryForwardChange(e.target.checked)} data-testid={`carry-forward-checkbox-${commitView.commitId}`} className="h-4 w-4" />
            <span>🔁 Carry this commit forward to next week</span>
          </label>
        </div>
      )}
    </div>
  );
}

// ── SubmitConfirmDialog ───────────────────────────────────────────────────────

function SubmitConfirmDialog({ achievedCount, partialCount, notAchievedCount, canceledCount, onConfirm, onCancel, isSubmitting }: {
  readonly achievedCount: number; readonly partialCount: number;
  readonly notAchievedCount: number; readonly canceledCount: number;
  readonly onConfirm: () => void; readonly onCancel: () => void; readonly isSubmitting: boolean;
}) {
  const summaryItems = [
    { label: "Achieved", count: achievedCount, cls: "bg-foreground/5 text-foreground" },
    { label: "Partial", count: partialCount, cls: "bg-neutral-100 text-muted" },
    { label: "Not Achieved", count: notAchievedCount, cls: "bg-neutral-200 text-foreground" },
    { label: "Canceled", count: canceledCount, cls: "bg-neutral-100 text-neutral-500" },
  ];
  return (
    <Dialog open onClose={onCancel} aria-label="Submit Reconciliation" data-testid="reconcile-submit-dialog">
      <DialogHeader>
        <DialogTitle>Submit Reconciliation?</DialogTitle>
        <DialogDescription>This will finalise the week and create an immutable snapshot. This cannot be undone.</DialogDescription>
      </DialogHeader>
      <div data-testid="reconcile-submit-summary" className="mb-4 grid grid-cols-2 gap-2">
        {summaryItems.map(({ label, count, cls }) => (
          <div key={label} className={cn("rounded-default px-3 py-2.5 text-center", cls)}>
            <div className="text-xl font-bold">{count}</div>
            <div className="text-xs">{label}</div>
          </div>
        ))}
      </div>
      <DialogFooter>
        <Button variant="secondary" onClick={onCancel} disabled={isSubmitting} data-testid="reconcile-submit-cancel">Cancel</Button>
        <Button variant="primary" onClick={onConfirm} disabled={isSubmitting} data-testid="reconcile-submit-confirm">
          {isSubmitting ? "Submitting…" : "Confirm Submission"}
        </Button>
      </DialogFooter>
    </Dialog>
  );
}

// ── ReconcilePage ─────────────────────────────────────────────────────────────

export default function ReconcilePage() {
  const { planId: planIdParam } = useParams<{ planId?: string }>();
  // If no planId in URL, auto-discover the current week's plan (only if reconcilable)
  const { data: currentPlanData, loading: currentPlanLoading } = useCurrentPlan();
  const currentPlan = currentPlanData?.plan;
  const isReconcilable = currentPlan?.state === "LOCKED" || currentPlan?.state === "RECONCILING";
  const discoveredPlanId = isReconcilable ? currentPlan?.id : undefined;
  const planId = planIdParam ?? discoveredPlanId;
  const planApi = usePlanApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const aiAssistanceEnabled = bridge.context.featureFlags.aiAssistanceEnabled;
  const { aiMode } = useAiMode();
  const { data, loading, error, refetch } = useReconcileView(planId);
  const { data: rcdoTreeData } = useRcdoTree();
  const rcdoLabels = useMemo(() => buildRcdoLabels(rcdoTreeData), [rcdoTreeData]);

  const [localOutcomes, setLocalOutcomes] = useState<Record<string, CommitOutcome>>({});
  const [localNotes, setLocalNotes] = useState<Record<string, string>>({});
  const [notesErrors, setNotesErrors] = useState<Record<string, string>>({});
  const [carryForwardSet, setCarryForwardSet] = useState<Set<string>>(new Set());
  const [carryForwardTarget, setCarryForwardTarget] = useState<string | null>(null);
  const [showSubmitDialog, setShowSubmitDialog] = useState(false);
  const [submitLoading, setSubmitLoading] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [savingOutcome, setSavingOutcome] = useState<string | null>(null);
  const [carryForwardLoading, setCarryForwardLoading] = useState(false);
  const [openingReconcile, setOpeningReconcile] = useState(false);
  const [openError, setOpenError] = useState<string | null>(null);

  // ── AI pre-fill state ─────────────────────────────────────────────────────
  /** Tracks which commitIds have AI-suggested outcomes not yet user-confirmed. */
  const [aiSuggestedOutcomes, setAiSuggestedOutcomes] = useState<Record<string, CommitOutcome>>({});
  /** True once AI pre-fill has been applied (prevents re-applying on re-renders). */
  const [aiPrefillApplied, setAiPrefillApplied] = useState(false);
  const [aiSuggestionId, setAiSuggestionId] = useState<string | undefined>(undefined);
  const [aiDraftSummary, setAiDraftSummary] = useState<string | null>(null);
  /**
   * AI-suggested notes stored as ghost/placeholder text.
   * These are NOT pre-filled into localNotes — shown as textarea placeholder
   * text only until the user types their own notes.
   */
  const [aiSuggestedNotes, setAiSuggestedNotes] = useState<Record<string, string>>({});

  const isReconciling = data?.plan.state === "RECONCILING";
  const { data: aiAssistData } = useAutoReconcileAssist(
    aiAssistanceEnabled && aiMode !== "on-demand" ? planId : null,
    userId,
    isReconciling ?? false,
  );

  // Apply AI pre-fill once, after both page data and AI data are ready.
  // Ghost/preview state: suggestions are stored in aiSuggestedOutcomes only.
  // They are NOT merged into localOutcomes until the user explicitly clicks
  // to accept them. Notes are stored as placeholder text, not pre-filled.
  useEffect(() => {
    if (!data || !aiAssistData || aiPrefillApplied) return;

    const newAiSuggested: Record<string, CommitOutcome> = {};
    const newAiNotes: Record<string, string> = {};

    for (const suggestion of aiAssistData.likelyOutcomes) {
      const commitExists = data.commits.some((cv) => cv.commitId === suggestion.commitId);
      if (commitExists) {
        const suggestedOutcome = suggestion.suggestedOutcome as CommitOutcome;
        newAiSuggested[suggestion.commitId] = suggestedOutcome;
        // Store rationale as ghost placeholder text (not pre-filled into textarea)
        if (NOTES_REQUIRED.has(suggestedOutcome) && suggestion.rationale?.trim()) {
          newAiNotes[suggestion.commitId] = suggestion.rationale;
        }
      }
    }

    if (Object.keys(newAiSuggested).length > 0) {
      setAiSuggestedOutcomes(newAiSuggested);
      setAiSuggestedNotes(newAiNotes);
    }

    // Pre-check carry-forward recommendations (checkboxes appear pre-checked).
    const eligibleCfIds = aiAssistData.carryForwardRecommendations
      .filter((r) => data.commits.some((cv) => cv.commitId === r.commitId))
      .map((r) => r.commitId);
    if (eligibleCfIds.length > 0) {
      setCarryForwardSet((prev) => {
        const next = new Set(prev);
        for (const id of eligibleCfIds) next.add(id);
        return next;
      });
    }

    setAiSuggestionId(aiAssistData.suggestionId);
    setAiDraftSummary(aiAssistData.draftSummary ?? null);
    setAiPrefillApplied(true);
  }, [data, aiAssistData, aiPrefillApplied]);

  const isPlanLocked = error !== null && (error.message.includes("LOCKED") || (error as { status?: number }).status === 400);
  const isReadOnly = data?.plan.state === "RECONCILED";

  const handleOpenReconciliation = useCallback(async () => {
    if (!planId) return;
    setOpeningReconcile(true); setOpenError(null);
    try { await planApi.openReconciliation(planId); refetch(); }
    catch (err) { setOpenError(err instanceof Error ? err.message : "Failed to open reconciliation"); }
    finally { setOpeningReconcile(false); }
  }, [planId, planApi, refetch]);

  const effectiveOutcomes: Record<string, CommitOutcome | null> = useMemo(() => {
    const map: Record<string, CommitOutcome | null> = {};
    for (const cv of data?.commits ?? []) {
      const local = localOutcomes[cv.commitId];
      map[cv.commitId] = local !== undefined ? local : cv.currentOutcome;
    }
    return map;
  }, [data, localOutcomes]);

  const effectiveNotes: Record<string, string> = useMemo(() => {
    const map: Record<string, string> = {};
    for (const cv of data?.commits ?? []) {
      const local = localNotes[cv.commitId];
      map[cv.commitId] = local !== undefined ? local : (cv.currentOutcomeNotes ?? "");
    }
    return map;
  }, [data, localNotes]);

  const handleOutcomeChange = useCallback(async (commitId: string, outcome: CommitOutcome) => {
    if (isReadOnly || !data) return;
    setLocalOutcomes((prev) => ({ ...prev, [commitId]: outcome }));
    setNotesErrors((prev) => { const next = { ...prev }; delete next[commitId]; return next; });
    if (!NOTES_REQUIRED.has(outcome)) setLocalNotes((prev) => ({ ...prev, [commitId]: "" }));
    if (!CARRY_FORWARD_ELIGIBLE.has(outcome)) { setCarryForwardSet((prev) => { const next = new Set(prev); next.delete(commitId); return next; }); }
    // When the user explicitly selects an outcome, remove the AI-suggested indicator.
    setAiSuggestedOutcomes((prev) => {
      if (!(commitId in prev)) return prev;
      const next = { ...prev };
      delete next[commitId];
      return next;
    });
    if (!NOTES_REQUIRED.has(outcome)) {
      setSavingOutcome(commitId);
      try { await planApi.setCommitOutcome(data.plan.id, commitId, { outcome }); refetch(); }
      catch { setLocalOutcomes((prev) => { const next = { ...prev }; delete next[commitId]; return next; }); }
      finally { setSavingOutcome(null); }
    }
  }, [isReadOnly, data, planApi, refetch]);

  const handleNotesSave = useCallback(async (commitId: string) => {
    if (isReadOnly || !data) return;
    const outcome = effectiveOutcomes[commitId];
    if (!outcome || !NOTES_REQUIRED.has(outcome)) return;
    const notes = effectiveNotes[commitId] ?? "";
    if (!notes.trim()) { setNotesErrors((prev) => ({ ...prev, [commitId]: "Notes are required for this outcome" })); return; }
    setSavingOutcome(commitId);
    try {
      await planApi.setCommitOutcome(data.plan.id, commitId, { outcome, notes });
      refetch(); setNotesErrors((prev) => { const next = { ...prev }; delete next[commitId]; return next; });
    } catch { /* ignore */ } finally { setSavingOutcome(null); }
  }, [isReadOnly, data, planApi, effectiveOutcomes, effectiveNotes, refetch]);

  function validateBeforeSubmit(): boolean {
    if (!data) return false;
    const newErrors: Record<string, string> = {}; let valid = true;
    for (const cv of data.commits) {
      const outcome = effectiveOutcomes[cv.commitId];
      if (!outcome) { newErrors[cv.commitId] = "Outcome is required"; valid = false; continue; }
      if (NOTES_REQUIRED.has(outcome)) { const notes = effectiveNotes[cv.commitId] ?? ""; if (!notes.trim()) { newErrors[cv.commitId] = "Notes are required for this outcome"; valid = false; } }
    }
    setNotesErrors(newErrors);
    return valid;
  }

  const handleSubmit = useCallback(async () => {
    if (!data) return;
    setSubmitLoading(true); setSubmitError(null);
    try {
      for (const cv of data.commits) {
        const outcome = effectiveOutcomes[cv.commitId];
        if (!outcome) continue;
        const notes = effectiveNotes[cv.commitId] ?? "";
        if (NOTES_REQUIRED.has(outcome)) {
          // Notes-required outcomes: save with notes (validated before submit).
          if (notes.trim()) await planApi.setCommitOutcome(data.plan.id, cv.commitId, { outcome, notes });
        } else if (outcome !== cv.currentOutcome) {
          // Non-notes outcomes: save if they differ from server state.
          // This handles AI-prefilled outcomes that were never explicitly clicked.
          await planApi.setCommitOutcome(data.plan.id, cv.commitId, { outcome });
        }
      }
      await planApi.submitReconciliation(data.plan.id);
      setShowSubmitDialog(false); refetch();
    } catch (err) { setSubmitError(err instanceof Error ? err.message : "Submission failed"); }
    finally { setSubmitLoading(false); }
  }, [data, effectiveOutcomes, effectiveNotes, planApi, refetch]);

  const handleCarryForwardConfirm = useCallback(async (targetWeekStart: string, reason: CarryForwardReason, reasonText?: string) => {
    if (!data || !carryForwardTarget) return;
    setCarryForwardLoading(true);
    try {
      await planApi.carryForward(data.plan.id, carryForwardTarget, { targetWeekStart, reason, ...(reasonText !== undefined ? { reasonText } : {}) });
      setCarryForwardTarget(null);
      setCarryForwardSet((prev) => { const next = new Set(prev); next.delete(carryForwardTarget); return next; });
      refetch();
    } catch (err) { setSubmitError(err instanceof Error ? err.message : "Carry-forward failed"); setCarryForwardTarget(null); }
    finally { setCarryForwardLoading(false); }
  }, [data, carryForwardTarget, planApi, refetch]);

  const outcomeSummary = useMemo(() => {
    const counts = { ACHIEVED: 0, PARTIALLY_ACHIEVED: 0, NOT_ACHIEVED: 0, CANCELED: 0 };
    for (const cv of data?.commits ?? []) { const o = effectiveOutcomes[cv.commitId]; if (o) counts[o] = (counts[o] ?? 0) + 1; }
    return counts;
  }, [data, effectiveOutcomes]);

  const allScopeEvents = useMemo(() => data?.commits.flatMap((cv) => cv.scopeChanges) ?? [], [data]);

  const canSubmit = !isReadOnly && data?.plan.state === "RECONCILING" && data.commits.every((cv) => effectiveOutcomes[cv.commitId] != null && (!NOTES_REQUIRED.has(effectiveOutcomes[cv.commitId]!) || effectiveNotes[cv.commitId]?.trim()));

  // ── Render ────────────────────────────────────────────────────────────────

  if (!planId) {
    // Still discovering the current plan — show loading state
    if (!planIdParam && currentPlanLoading) {
      return (
        <div data-testid="page-reconcile" className="flex flex-col gap-4">
          <h2 className="m-0 text-xl font-bold">Reconcile</h2>
          <div role="status" className="text-sm text-muted">Loading plan…</div>
        </div>
      );
    }
    return (
      <div data-testid="page-reconcile" className="flex flex-col gap-4">
        <h2 className="m-0 text-xl font-bold">Reconcile</h2>
        <p className="text-sm text-muted">
          No plan available for reconciliation this week. Navigate to{" "}
          <a href="/weekly/my-week" className="text-primary hover:underline">My Week</a>
          {" "}and lock your plan first.
        </p>
      </div>
    );
  }

  if (loading) {
    return (
      <div data-testid="page-reconcile" className="flex flex-col gap-4">
        <h2 className="m-0 text-xl font-bold">Reconcile</h2>
        <div role="status" aria-label="Loading reconciliation view" data-testid="reconcile-loading" className="text-sm text-muted">Loading…</div>
      </div>
    );
  }

  if (error) {
    if (isPlanLocked) {
      return (
        <div data-testid="page-reconcile" className="flex flex-col gap-4">
          <h2 className="m-0 text-xl font-bold">Reconcile</h2>
          <Card data-testid="reconcile-locked-prompt" className="max-w-[480px]">
            <CardContent className="py-4">
              <p className="m-0 mb-3 font-semibold flex items-center gap-1.5"><Lock className="h-4 w-4" /> Plan is locked — ready for reconciliation</p>
              <p className="m-0 mb-4 text-sm text-muted">The week is over. Open reconciliation to record outcomes for each commitment.</p>
              {openError && <p role="alert" className="text-sm text-danger mb-3">{openError}</p>}
              <Button variant="primary" onClick={() => void handleOpenReconciliation()} disabled={openingReconcile} data-testid="open-reconciliation-btn">
                {openingReconcile ? "Opening…" : "Open Reconciliation →"}
              </Button>
            </CardContent>
          </Card>
        </div>
      );
    }
    return (
      <div data-testid="page-reconcile" className="flex flex-col gap-4">
        <h2 className="m-0 text-xl font-bold">Reconcile</h2>
        <div role="alert" data-testid="reconcile-error" className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2.5 text-sm text-danger">
          Failed to load reconciliation view: {error.message}
        </div>
      </div>
    );
  }

  if (!data) return null;

  const carryForwardCommit = carryForwardTarget ? data.commits.find((cv) => cv.commitId === carryForwardTarget) : null;

  return (
    <div data-testid="page-reconcile" className="flex flex-col gap-4">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">Reconcile</h2>
        <Badge data-testid="reconcile-plan-state" variant={data.plan.state === "RECONCILED" ? "reconciled" : "reconciling"}>
          {data.plan.state}
        </Badge>
      </div>

      {/* Stats bar */}
      <Card data-testid="reconcile-stats-bar">
        <CardContent className="py-3 flex gap-6 flex-wrap text-sm">
          <div><span className="font-bold">{data.commitCount}</span> <span className="text-muted">commits</span></div>
          <div><span className="font-bold">{data.outcomesSetCount}</span> <span className="text-muted">outcomes set</span></div>
          <div><span className="font-bold">{data.baselineTotalPoints} pts</span> <span className="text-muted">baseline</span></div>
          <div><span className="font-bold">{data.currentTotalPoints} pts</span> <span className="text-muted">current</span></div>
        </CardContent>
      </Card>

      {/* AI pre-fill banner — shown when AI has pre-populated outcomes */}
      {aiPrefillApplied && !isReadOnly && Object.keys(aiSuggestedOutcomes).length > 0 && (
        <div
          data-testid="ai-prefill-banner"
          className="flex items-start gap-2.5 rounded-default border border-primary/20 bg-primary/5 px-4 py-3"
        >
          <Sparkles className="h-4 w-4 text-primary mt-0.5 shrink-0" aria-hidden="true" />
          <div className="flex-1 min-w-0">
            <p className="m-0 text-sm font-semibold text-foreground">
              AI has suggested likely outcomes — click each to accept
            </p>
            <p className="m-0 mt-0.5 text-xs text-muted">
              Suggestions are shown in blue below. Click to accept, or select a different outcome.
            </p>
          </div>
          {aiSuggestionId && (
            <AiFeedbackButtons suggestionId={aiSuggestionId} className="shrink-0" />
          )}
        </div>
      )}

      {/* AI draft summary — auto-generated week summary displayed as the header context */}
      {aiDraftSummary && (
        <Card data-testid="ai-draft-summary">
          <CardHeader>
            <div className="flex items-center gap-2">
              <Bot className="h-4 w-4 text-primary shrink-0" aria-hidden="true" />
              <span className="text-sm font-semibold text-foreground">AI Week Summary</span>
            </div>
            {aiSuggestionId && (
              <AiFeedbackButtons suggestionId={aiSuggestionId} className="shrink-0" />
            )}
          </CardHeader>
          <CardContent>
            <p className="m-0 text-sm text-foreground leading-relaxed">{aiDraftSummary}</p>
          </CardContent>
        </Card>
      )}

      {submitError && (
        <div role="alert" data-testid="reconcile-submit-error" className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2.5 text-sm text-danger">{submitError}</div>
      )}

      {isReadOnly && (
        <div data-testid="reconcile-readonly-banner" className="flex items-center gap-2 rounded-default border border-foreground/20 bg-foreground/5 px-4 py-3 text-sm text-foreground">
          <Check className="h-4 w-4 shrink-0" aria-hidden="true" />
          This plan has been fully reconciled and is now read-only.
        </div>
      )}

      {/* Commit rows */}
      <div data-testid="reconcile-commit-list" className="flex flex-col gap-3.5">
        {data.commits.map((cv) => {
          const commitId = cv.commitId;
          const outcome = effectiveOutcomes[commitId] ?? null;
          const notes = effectiveNotes[commitId] ?? "";
          const saving = savingOutcome === commitId;
          return (
            <div key={commitId} className="relative">
              {saving && (
                <div data-testid={`saving-indicator-${commitId}`} className="absolute top-1.5 right-1.5 text-[0.65rem] text-muted italic">Saving…</div>
              )}
              <ReconcileCommitRow
                commitView={cv} outcome={outcome} notes={notes}
                carryForward={carryForwardSet.has(commitId)}
                notesError={notesErrors[commitId] ?? null}
                isReadOnly={isReadOnly}
                rcdoLabels={rcdoLabels}
                aiSuggestedOutcome={aiSuggestedOutcomes[commitId]}
                aiSuggestedNote={aiSuggestedNotes[commitId]}
                onOutcomeChange={(o) => void handleOutcomeChange(commitId, o)}
                onNotesChange={(n) => setLocalNotes((prev) => ({ ...prev, [commitId]: n }))}
                onCarryForwardChange={(checked) => {
                  if (checked) setCarryForwardTarget(commitId);
                  setCarryForwardSet((prev) => { const next = new Set(prev); if (checked) next.add(commitId); else next.delete(commitId); return next; });
                }}
              />
              {!isReadOnly && outcome && NOTES_REQUIRED.has(outcome) && (
                <Button variant="secondary" size="sm" type="button" onClick={() => void handleNotesSave(commitId)} data-testid={`save-notes-${commitId}`} className="mt-1">
                  Save notes
                </Button>
              )}
            </div>
          );
        })}
      </div>

      {/* Scope changes */}
      {allScopeEvents.length > 0 && (
        <section aria-labelledby="scope-changes-heading">
          <h3 id="scope-changes-heading" className="m-0 mb-2.5 text-base font-semibold">Post-lock Scope Changes</h3>
          <ScopeChangeTimeline events={allScopeEvents} />
        </section>
      )}

      {/* Submit section */}
      {!isReadOnly && (
        <Card data-testid="reconcile-submit-section">
          <CardHeader>
            <div>
              <p className="m-0 font-semibold text-sm">Ready to submit?</p>
              <p className="m-0 mt-1 text-xs text-muted">{data.outcomesSetCount} / {data.commitCount} outcomes set. All commits must have outcomes before submitting.</p>
            </div>
            <Button
              variant={canSubmit ? "primary" : "secondary"}
              disabled={!canSubmit}
              onClick={() => { if (validateBeforeSubmit()) setShowSubmitDialog(true); }}
              data-testid="reconcile-submit-btn"
            >
              Submit Reconciliation
            </Button>
          </CardHeader>
        </Card>
      )}

      {showSubmitDialog && (
        <SubmitConfirmDialog achievedCount={outcomeSummary.ACHIEVED} partialCount={outcomeSummary.PARTIALLY_ACHIEVED} notAchievedCount={outcomeSummary.NOT_ACHIEVED} canceledCount={outcomeSummary.CANCELED} onConfirm={() => void handleSubmit()} onCancel={() => setShowSubmitDialog(false)} isSubmitting={submitLoading} />
      )}

      {carryForwardTarget && carryForwardCommit && (
        <CarryForwardDialog
          commit={{ id: carryForwardCommit.commitId, planId: data.plan.id, ownerUserId: data.plan.ownerUserId, title: carryForwardCommit.currentTitle, chessPiece: carryForwardCommit.currentChessPiece, priorityOrder: 1, carryForwardStreak: 0, createdAt: "", updatedAt: "" }}
          onConfirm={(targetWeekStart, reason, reasonText) => void handleCarryForwardConfirm(targetWeekStart, reason, reasonText)}
          onCancel={() => {
            setCarryForwardTarget(null);
            setCarryForwardSet((prev) => { const next = new Set(prev); next.delete(carryForwardTarget); return next; });
          }}
          isSubmitting={carryForwardLoading}
        />
      )}
    </div>
  );
}

/**
 * Tickets page — native ticket management.
 * Route: /weekly/tickets
 */
import { useState, useCallback, useMemo } from "react";
import { useSearchParams } from "react-router-dom";
import { X } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Skeleton } from "../components/ui/Skeleton.js";
import { useHostBridge } from "../host/HostProvider.js";
import { useTicketList, useTicketApi, useTicket } from "../api/ticketHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { useTeamMembers } from "../api/teamHooks.js";
import { TicketListView, type TicketSortColumn } from "../components/tickets/TicketListView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { TicketDetailView } from "../components/tickets/TicketDetailView.js";
import type { TicketListParams, TicketStatus, TicketPriority, CreateTicketPayload } from "../api/ticketTypes.js";
import { TICKET_STATUS_LABELS, TICKET_PRIORITY_LABELS } from "../api/ticketTypes.js";

const TICKET_STATUSES: TicketStatus[] = ["TODO", "IN_PROGRESS", "BLOCKED", "DONE", "CANCELED"];
const TICKET_PRIORITIES: TicketPriority[] = ["CRITICAL", "HIGH", "MEDIUM", "LOW"];
const PAGE_SIZE = 20;

function paramsToListParams(sp: URLSearchParams): TicketListParams & { sortBy: TicketSortColumn; sortDir: "asc" | "desc"; page: number } {
  const status = sp.get("status") as TicketStatus | null;
  const assignee = sp.get("assignee");
  const team = sp.get("team");
  const rcdo = sp.get("rcdo");
  const week = sp.get("week");
  const priority = sp.get("priority") as TicketPriority | null;
  return {
    ...(status ? { status } : {}), ...(assignee ? { assigneeUserId: assignee } : {}),
    ...(team ? { teamId: team } : {}), ...(rcdo ? { rcdoNodeId: rcdo } : {}),
    ...(week ? { targetWeek: week } : {}), ...(priority ? { priority } : {}),
    page: sp.get("page") ? Number(sp.get("page")) : 1, pageSize: PAGE_SIZE,
    sortBy: (sp.get("sortBy") as TicketSortColumn | null) ?? "updatedAt",
    sortDir: sp.get("sortDir") === "asc" ? "asc" : "desc",
  };
}

function buildRcdoLabels(nodes: ReturnType<typeof useRcdoTree>["data"]): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(ns: typeof nodes, path: string[] = []) {
    if (!ns) return;
    for (const n of ns) { const nextPath = [...path, n.title]; map[n.id] = nextPath.join(" > "); traverse(n.children, nextPath); }
  }
  traverse(nodes ?? []);
  return map;
}

const inputCls = "h-8 rounded-default border border-border bg-surface px-2.5 text-xs text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50";
const labelCls = "text-[0.65rem] font-bold uppercase tracking-wider text-muted mb-0.5 block";

function TicketFilters({ params, onParamsChange, onClearFilters }: {
  params: ReturnType<typeof paramsToListParams>;
  onParamsChange: (patch: Partial<ReturnType<typeof paramsToListParams>>) => void;
  onClearFilters: () => void;
}) {
  const hasFilter = params.status ?? params.assigneeUserId ?? params.teamId ?? params.rcdoNodeId ?? params.targetWeek ?? params.priority;
  return (
    <div data-testid="ticket-filters" className="rounded-default border border-border bg-surface px-4 py-3 flex gap-3 flex-wrap items-end">
      <div className="flex flex-col">
        <label htmlFor="tf-status-filter" className={labelCls}>Status</label>
        <select id="tf-status-filter" value={params.status ?? ""} onChange={(e) => { const v = e.target.value as TicketStatus | ""; onParamsChange({ ...(v ? { status: v } : {}), page: 1 }); }} data-testid="filter-status" className={inputCls}>
          <option value="">All statuses</option>
          {TICKET_STATUSES.map((s) => <option key={s} value={s}>{TICKET_STATUS_LABELS[s]}</option>)}
        </select>
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-priority-filter" className={labelCls}>Priority</label>
        <select id="tf-priority-filter" value={params.priority ?? ""} onChange={(e) => { const v = e.target.value as TicketPriority | ""; onParamsChange({ ...(v ? { priority: v } : {}), page: 1 }); }} data-testid="filter-priority" className={inputCls}>
          <option value="">All priorities</option>
          {TICKET_PRIORITIES.map((p) => <option key={p} value={p}>{TICKET_PRIORITY_LABELS[p]}</option>)}
        </select>
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-assignee-filter" className={labelCls}>Assignee</label>
        <input id="tf-assignee-filter" type="text" placeholder="User ID…" value={params.assigneeUserId ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { assigneeUserId: v } : {}), page: 1 }); }} data-testid="filter-assignee" className={`${inputCls} min-w-[110px]`} />
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-team-filter" className={labelCls}>Team</label>
        <input id="tf-team-filter" type="text" placeholder="Team ID…" value={params.teamId ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { teamId: v } : {}), page: 1 }); }} data-testid="filter-team" className={`${inputCls} min-w-[110px]`} />
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-rcdo-filter" className={labelCls}>RCDO</label>
        <input id="tf-rcdo-filter" type="text" placeholder="RCDO node ID…" value={params.rcdoNodeId ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { rcdoNodeId: v } : {}), page: 1 }); }} data-testid="filter-rcdo" className={`${inputCls} min-w-[110px]`} />
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-week-filter" className={labelCls}>Target Week</label>
        <input id="tf-week-filter" type="date" value={params.targetWeek ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { targetWeek: v } : {}), page: 1 }); }} data-testid="filter-week" className={inputCls} />
      </div>
      {hasFilter && (
        <Button variant="secondary" size="sm" onClick={onClearFilters} data-testid="filter-clear-all" className="self-end">
          <X className="h-3 w-3" />Clear all
        </Button>
      )}
    </div>
  );
}

export default function Tickets() {
  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;
  const currentTeamId = bridge.context.currentTeam?.id;

  const [searchParams, setSearchParams] = useSearchParams();
  const listParams = useMemo(() => paramsToListParams(searchParams), [searchParams]);
  const { data: rcdoTreeData } = useRcdoTree();
  const rcdoLabels = useMemo(() => buildRcdoLabels(rcdoTreeData), [rcdoTreeData]);
  const { data: ticketPage, loading: ticketsLoading, refetch: refetchTickets } = useTicketList(listParams);
  const ticketApi = useTicketApi();

  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);
  const { data: ticketDetail, loading: detailLoading, refetch: refetchDetail } = useTicket(selectedTicketId);
  const { data: teamMembers } = useTeamMembers(currentTeamId ?? null);
  type FormMode = "create" | "create-from-commit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [formInitialValues, setFormInitialValues] = useState<Partial<CreateTicketPayload>>({});

  const updateParams = useCallback((patch: Partial<ReturnType<typeof paramsToListParams>>) => {
    setSearchParams((prev) => {
      const next = new URLSearchParams(prev);
      const merged = { ...paramsToListParams(prev), ...patch };
      const pairs: [string, string][] = [
        ...(merged.status ? [["status", merged.status] as [string, string]] : []),
        ...(merged.assigneeUserId ? [["assignee", merged.assigneeUserId] as [string, string]] : []),
        ...(merged.teamId ? [["team", merged.teamId] as [string, string]] : []),
        ...(merged.rcdoNodeId ? [["rcdo", merged.rcdoNodeId] as [string, string]] : []),
        ...(merged.targetWeek ? [["week", merged.targetWeek] as [string, string]] : []),
        ...(merged.priority ? [["priority", merged.priority] as [string, string]] : []),
        ...(merged.page && merged.page !== 1 ? [["page", String(merged.page)] as [string, string]] : []),
        ...(merged.sortBy && merged.sortBy !== "updatedAt" ? [["sortBy", merged.sortBy] as [string, string]] : []),
        ...(merged.sortDir && merged.sortDir !== "desc" ? [["sortDir", merged.sortDir] as [string, string]] : []),
      ];
      Array.from(next.keys()).forEach((k) => next.delete(k));
      pairs.forEach(([k, v]) => next.set(k, v));
      return next;
    });
  }, [setSearchParams]);

  const handleCreateTicket = useCallback(async (payload: CreateTicketPayload) => {
    await ticketApi.createTicket(payload);
    setFormMode(null); setFormInitialValues({});
    refetchTickets();
  }, [ticketApi, refetchTickets]);

  const handleStatusTransition = useCallback(async (ticketId: string, newStatus: TicketStatus) => {
    await ticketApi.transitionStatus(ticketId, newStatus, currentUserId);
    refetchDetail(); refetchTickets();
  }, [ticketApi, refetchDetail, refetchTickets, currentUserId]);

  const handleAssigneeChange = useCallback(async (ticketId: string, assigneeUserId: string) => {
    await ticketApi.updateTicket(ticketId, assigneeUserId ? { assigneeUserId } : {});
    refetchDetail(); refetchTickets();
  }, [ticketApi, refetchDetail, refetchTickets]);

  return (
    <div className="flex flex-col gap-4" data-testid="page-tickets">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">Tickets</h2>
        <Button variant="primary" onClick={() => { setFormInitialValues({ reporterUserId: currentUserId, ...(currentTeamId ? { teamId: currentTeamId } : {}) }); setFormMode("create"); }} data-testid="create-ticket-btn">
          + Create Ticket
        </Button>
      </div>

      <TicketFilters params={listParams} onParamsChange={updateParams} onClearFilters={() => setSearchParams(new URLSearchParams())} />

      {ticketPage && (
        <div data-testid="ticket-count" className="text-sm text-muted">
          {ticketPage.total} ticket{ticketPage.total !== 1 ? "s" : ""}
        </div>
      )}

      <div className={`flex gap-4 items-start ${selectedTicketId ? "flex-nowrap" : "flex-wrap"}`}>
        <div style={{ flex: selectedTicketId ? "0 0 55%" : "1 1 100%", minWidth: 0 }}>
          <TicketListView
            tickets={ticketPage?.items ?? []}
            total={ticketPage?.total ?? 0}
            page={listParams.page ?? 1}
            pageSize={PAGE_SIZE}
            sortBy={listParams.sortBy}
            sortDir={listParams.sortDir}
            loading={ticketsLoading}
            onPageChange={(p) => updateParams({ page: p })}
            onSortChange={(col, dir) => updateParams({ sortBy: col, sortDir: dir })}
            onSelectTicket={(id) => setSelectedTicketId(id === selectedTicketId ? null : id)}
            rcdoLabels={rcdoLabels}
          />
        </div>

        {selectedTicketId && (
          <div data-testid="ticket-detail-panel" className="flex-1 min-w-[280px] sticky top-4">
            {detailLoading && (
              <div data-testid="ticket-detail-loading" role="status" aria-label="Loading ticket details" className="p-4 flex flex-col gap-3">
                <span className="sr-only">Loading ticket details…</span>
                <Skeleton className="h-6 w-3/4" />
                <Skeleton className="h-4 w-1/2" />
                <Skeleton className="h-20 w-full" />
                <div className="flex gap-2">
                  <Skeleton className="h-5 w-16 rounded-sm" />
                  <Skeleton className="h-5 w-16 rounded-sm" />
                </div>
              </div>
            )}
            {!detailLoading && ticketDetail && (
              <TicketDetailView
                ticket={ticketDetail}
                onStatusTransition={handleStatusTransition}
                onAssigneeChange={handleAssigneeChange}
                teamMembers={teamMembers ?? []}
                {...(ticketDetail.rcdoNodeId && rcdoLabels[ticketDetail.rcdoNodeId] ? { rcdoPath: rcdoLabels[ticketDetail.rcdoNodeId] } : {})}
                onClose={() => setSelectedTicketId(null)}
                onEdit={() => {
                  setFormInitialValues({
                    title: ticketDetail.title,
                    ...(ticketDetail.description ? { description: ticketDetail.description } : {}),
                    status: ticketDetail.status, priority: ticketDetail.priority,
                    ...(ticketDetail.assigneeUserId ? { assigneeUserId: ticketDetail.assigneeUserId } : {}),
                    reporterUserId: ticketDetail.reporterUserId, teamId: ticketDetail.teamId,
                    ...(ticketDetail.rcdoNodeId ? { rcdoNodeId: ticketDetail.rcdoNodeId } : {}),
                    ...(ticketDetail.estimatePoints != null ? { estimatePoints: ticketDetail.estimatePoints } : {}),
                    ...(ticketDetail.targetWeekStartDate ? { targetWeekStartDate: ticketDetail.targetWeekStartDate } : {}),
                  });
                  setFormMode("create");
                }}
              />
            )}
          </div>
        )}
      </div>

      {formMode !== null && (
        <TicketForm
          mode="create"
          initialValues={formInitialValues}
          currentUserId={currentUserId}
          {...(currentTeamId ? { currentTeamId } : {})}
          rcdoTree={rcdoTreeData ?? []}
          onSubmit={handleCreateTicket}
          onCancel={() => { setFormMode(null); setFormInitialValues({}); }}
        />
      )}
    </div>
  );
}

/**
 * TicketListView — sortable, paginated table of tickets.
 */
import { ChevronLeft, ChevronRight, ArrowUpDown, ArrowUp, ArrowDown, Ticket as TicketIcon } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { Skeleton } from "../ui/Skeleton.js";
import { EmptyState } from "../shared/EmptyState.js";
import { cn } from "../../lib/utils.js";
import type { TicketSummaryResponse, TicketStatus, TicketPriority } from "../../api/ticketTypes.js";
import { TICKET_STATUS_LABELS, TICKET_PRIORITY_LABELS } from "../../api/ticketTypes.js";

export type TicketSortColumn = "key" | "title" | "status" | "priority" | "updatedAt";

export interface TicketListViewProps {
  readonly tickets: TicketSummaryResponse[];
  readonly total: number;
  readonly page: number;
  readonly pageSize: number;
  readonly sortBy: TicketSortColumn;
  readonly sortDir: "asc" | "desc";
  readonly loading: boolean;
  readonly onPageChange: (page: number) => void;
  readonly onSortChange: (col: TicketSortColumn, dir: "asc" | "desc") => void;
  readonly onSelectTicket: (ticketId: string) => void;
  readonly rcdoLabels?: Record<string, string>;
}

const STATUS_BADGE_VARIANT: Record<TicketStatus, "default" | "primary" | "success" | "danger"> = {
  TODO: "default", IN_PROGRESS: "primary", DONE: "success", CANCELED: "default", BLOCKED: "danger",
};
const PRIORITY_BADGE_VARIANT: Record<TicketPriority, "danger" | "warning" | "primary" | "default"> = {
  CRITICAL: "danger", HIGH: "warning", MEDIUM: "primary", LOW: "default",
};

const SORTABLE_COLUMNS: { col: TicketSortColumn; label: string }[] = [
  { col: "key", label: "Key" }, { col: "title", label: "Title" },
  { col: "status", label: "Status" }, { col: "priority", label: "Priority" }, { col: "updatedAt", label: "Updated" },
];

const thCls = "px-2.5 py-2 text-left text-[0.7rem] font-bold uppercase tracking-wider text-muted border-b-2 border-border whitespace-nowrap cursor-pointer select-none hover:text-foreground transition-colors";
const tdCls = "px-2.5 py-2 text-sm border-b border-border align-middle";

export function TicketListView({ tickets, total, page, pageSize, sortBy, sortDir, loading, onPageChange, onSortChange, onSelectTicket, rcdoLabels = {} }: TicketListViewProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  function handleSortClick(col: TicketSortColumn) {
    if (sortBy === col) { onSortChange(col, sortDir === "asc" ? "desc" : "asc"); }
    else { onSortChange(col, "asc"); }
  }

  return (
    <div data-testid="ticket-list-view" className="flex flex-col gap-3">
      {loading && (
        <div role="status" aria-label="Loading tickets" data-testid="ticket-list-loading" className="flex flex-col gap-2">
          <span className="sr-only">Loading tickets…</span>
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <tbody>
                {Array.from({ length: 5 }, (_, i) => (
                  <tr key={i} className="border-b border-border">
                    <td className="px-2.5 py-2 w-20"><Skeleton className="h-4 w-16" /></td>
                    <td className="px-2.5 py-2"><Skeleton className="h-4 w-full" /></td>
                    <td className="px-2.5 py-2 w-24"><Skeleton className="h-5 w-20 rounded-sm" /></td>
                    <td className="px-2.5 py-2 w-24"><Skeleton className="h-5 w-16 rounded-sm" /></td>
                    <td className="px-2.5 py-2 w-28"><Skeleton className="h-4 w-24" /></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {!loading && tickets.length === 0 && (
        <EmptyState
          data-testid="ticket-list-empty"
          icon={<TicketIcon className="h-9 w-9" />}
          title="No tickets found"
          description="No tickets match your current filters. Try adjusting your search or creating a new ticket."
        />
      )}

      {!loading && tickets.length > 0 && (
        <div className="overflow-x-auto">
          <table data-testid="ticket-list-table" className="w-full border-collapse text-sm">
            <thead>
              <tr>
                {SORTABLE_COLUMNS.map(({ col, label }) => (
                  <th key={col} className={thCls} onClick={() => handleSortClick(col)} data-testid={`sort-col-${col}`} aria-sort={sortBy === col ? (sortDir === "asc" ? "ascending" : "descending") : "none"}>
                    <span className="inline-flex items-center gap-1">
                      {label}
                      {sortBy === col
                        ? sortDir === "asc" ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                        : <ArrowUpDown className="h-3 w-3 opacity-30" />}
                    </span>
                  </th>
                ))}
                <th className={thCls}>Assignee</th>
                <th className={thCls}>Team</th>
                <th className={thCls}>RCDO</th>
                <th className={thCls}>Target Week</th>
              </tr>
            </thead>
            <tbody>
              {tickets.map((ticket) => (
                <tr key={ticket.id} data-testid={`ticket-row-${ticket.id}`} onClick={() => onSelectTicket(ticket.id)} className="cursor-pointer hover:bg-background/80 transition-colors">
                  <td className={tdCls}><span data-testid={`ticket-key-${ticket.id}`} className="font-mono text-xs font-semibold">{ticket.key}</span></td>
                  <td className={cn(tdCls, "max-w-[250px]")}><span data-testid={`ticket-title-${ticket.id}`} className="block overflow-hidden text-ellipsis whitespace-nowrap">{ticket.title}</span></td>
                  <td className={tdCls}><Badge variant={STATUS_BADGE_VARIANT[ticket.status]}>{TICKET_STATUS_LABELS[ticket.status]}</Badge></td>
                  <td className={tdCls}><Badge variant={PRIORITY_BADGE_VARIANT[ticket.priority]}>{TICKET_PRIORITY_LABELS[ticket.priority]}</Badge></td>
                  <td className={cn(tdCls, "text-xs text-muted")}>{new Date(ticket.updatedAt).toLocaleDateString()}</td>
                  <td className={cn(tdCls, "text-xs")}>{ticket.assigneeDisplayName ?? (ticket.assigneeUserId ? ticket.assigneeUserId.slice(0, 8) + "…" : <span className="text-muted">—</span>)}</td>
                  <td className={cn(tdCls, "text-xs")}>{ticket.teamName ?? ticket.teamId.slice(0, 8) + "…"}</td>
                  <td className={cn(tdCls, "text-xs text-muted")}>{ticket.rcdoNodeId ? (rcdoLabels[ticket.rcdoNodeId] ?? ticket.rcdoNodeId) : "—"}</td>
                  <td className={cn(tdCls, "text-xs")}>{ticket.targetWeekStartDate ?? <span className="text-muted">—</span>}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {total > pageSize && (
        <div data-testid="ticket-list-pagination" className="flex items-center gap-2 justify-end flex-wrap">
          <span className="text-xs text-muted">{(page - 1) * pageSize + 1}–{Math.min(page * pageSize, total)} of {total}</span>
          <Button variant="secondary" size="sm" onClick={() => onPageChange(page - 1)} disabled={page <= 1} data-testid="ticket-page-prev">
            <ChevronLeft className="h-3.5 w-3.5" />Prev
          </Button>
          <span data-testid="ticket-page-indicator" className="text-xs">{page} / {totalPages}</span>
          <Button variant="secondary" size="sm" onClick={() => onPageChange(page + 1)} disabled={page >= totalPages} data-testid="ticket-page-next">
            Next<ChevronRight className="h-3.5 w-3.5" />
          </Button>
        </div>
      )}
    </div>
  );
}

/**
 * TicketDetailView — full ticket detail panel.
 */
import { useState, useCallback } from "react";
import { X, Pencil } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import type { TicketResponse, TicketStatus, TicketStatusHistory, LinkedCommitEntry } from "../../api/ticketTypes.js";
import type { TeamMember } from "../../api/teamTypes.js";
import type { CommitOutcome } from "../../api/planTypes.js";
import { TICKET_STATUS_LABELS, TICKET_STATUS_TRANSITIONS, TICKET_PRIORITY_LABELS } from "../../api/ticketTypes.js";

export interface TicketDetailViewProps {
  readonly ticket: TicketResponse;
  readonly onStatusTransition: (ticketId: string, newStatus: TicketStatus) => Promise<void>;
  readonly onAssigneeChange: (ticketId: string, assigneeUserId: string) => Promise<void>;
  /** Team members for the assignee dropdown. Falls back to text input when empty/undefined. */
  readonly teamMembers?: readonly TeamMember[];
  readonly rcdoPath?: string;
  readonly onClose?: () => void;
  readonly onEdit?: () => void;
}

const STATUS_BADGE_VARIANT: Record<TicketStatus, "default" | "primary" | "success" | "danger"> = {
  TODO: "default", IN_PROGRESS: "primary", DONE: "success", CANCELED: "default", BLOCKED: "danger",
};

const OUTCOME_LABELS: Record<CommitOutcome, string> = {
  ACHIEVED: "✓ Achieved", PARTIALLY_ACHIEVED: "◑ Partial", NOT_ACHIEVED: "✗ Not achieved", CANCELED: "— Canceled",
};
const OUTCOME_CLS: Record<CommitOutcome, string> = {
  ACHIEVED: "text-success", PARTIALLY_ACHIEVED: "text-warning", NOT_ACHIEVED: "text-danger", CANCELED: "text-muted",
};

const shCls = "text-[0.75rem] font-bold uppercase tracking-wider text-muted m-0 mb-2";
const metaRowCls = "flex gap-2 text-sm items-baseline";
const metaLabelCls = "font-semibold min-w-[100px] shrink-0 text-muted";

function StatusHistoryTimeline({ history }: { history: TicketStatusHistory[] }) {
  if (history.length === 0) {
    return <p data-testid="status-history-empty" className="text-sm text-muted">No status changes recorded.</p>;
  }
  return (
    <ol data-testid="status-history-timeline" className="list-none m-0 p-0 flex flex-col gap-2">
      {[...history].reverse().map((entry) => (
        <li key={entry.id} data-testid={`history-entry-${entry.id}`} className="flex items-start gap-2.5 text-xs">
          <span className="mt-1 h-2 w-2 rounded-full bg-primary shrink-0" />
          <div>
            <span className="text-muted">{new Date(entry.changedAt).toLocaleString()}</span>
            {" — "}
            {entry.fromStatus ? <><strong>{TICKET_STATUS_LABELS[entry.fromStatus]}</strong>{" → "}</> : null}
            <strong>{TICKET_STATUS_LABELS[entry.toStatus]}</strong>
            {entry.note && <span className="text-muted"> ({entry.note})</span>}
          </div>
        </li>
      ))}
    </ol>
  );
}

function LinkedCommitsList({ commits }: { commits: LinkedCommitEntry[] }) {
  if (commits.length === 0) {
    return <p data-testid="linked-commits-empty" className="text-sm text-muted">No linked commits.</p>;
  }
  return (
    <ul data-testid="linked-commits-list" className="list-none m-0 p-0 flex flex-col gap-1.5">
      {commits.map((c) => (
        <li key={c.commitId} data-testid={`linked-commit-${c.commitId}`}
          className="rounded-default border border-border bg-background px-3 py-2 text-sm flex justify-between items-center flex-wrap gap-1.5">
          <div>
            <span className="font-semibold">{c.commitTitle}</span>
            <span className="ml-2 text-xs text-muted">{c.weekStartDate} · {c.chessPiece}{c.estimatePoints != null ? ` · ${c.estimatePoints}pts` : ""}</span>
          </div>
          {c.outcome && (
            <span data-testid={`linked-commit-outcome-${c.commitId}`} className={cn("text-xs font-semibold", OUTCOME_CLS[c.outcome])}>
              {OUTCOME_LABELS[c.outcome]}
            </span>
          )}
        </li>
      ))}
    </ul>
  );
}

export function TicketDetailView({ ticket, onStatusTransition, onAssigneeChange, teamMembers, rcdoPath, onClose, onEdit }: TicketDetailViewProps) {
  const [transitioning, setTransitioning] = useState<TicketStatus | null>(null);
  const [transitionError, setTransitionError] = useState<string | null>(null);
  const [assigneeInput, setAssigneeInput] = useState(ticket.assigneeUserId ?? "");
  const [assigneeSaving, setAssigneeSaving] = useState(false);
  const [assigneeError, setAssigneeError] = useState<string | null>(null);

  const nextStatuses = TICKET_STATUS_TRANSITIONS[ticket.status];

  const handleTransition = useCallback(async (newStatus: TicketStatus) => {
    setTransitioning(newStatus); setTransitionError(null);
    try { await onStatusTransition(ticket.id, newStatus); }
    catch (err) { setTransitionError(err instanceof Error ? err.message : "Status transition failed."); }
    finally { setTransitioning(null); }
  }, [ticket.id, onStatusTransition]);

  const handleAssigneeChange = useCallback(async () => {
    setAssigneeSaving(true); setAssigneeError(null);
    try { await onAssigneeChange(ticket.id, assigneeInput.trim()); }
    catch (err) { setAssigneeError(err instanceof Error ? err.message : "Assignment change failed."); }
    finally { setAssigneeSaving(false); }
  }, [ticket.id, assigneeInput, onAssigneeChange]);

  return (
    <div data-testid="ticket-detail-view" className="rounded-default border border-border bg-surface flex flex-col gap-0 overflow-hidden">
      {/* Header */}
      <div className="px-5 py-4 border-b border-border flex items-start justify-between gap-4 flex-wrap">
        <div className="flex flex-col gap-1.5 flex-1">
          <div className="flex items-center gap-2 flex-wrap">
            <span data-testid="ticket-detail-key" className="font-mono text-xs font-bold text-muted">{ticket.key}</span>
            <Badge variant={STATUS_BADGE_VARIANT[ticket.status]} data-testid="ticket-detail-status-badge">
              {TICKET_STATUS_LABELS[ticket.status]}
            </Badge>
          </div>
          <h2 data-testid="ticket-detail-title" className="m-0 text-lg font-bold">{ticket.title}</h2>
        </div>
        <div className="flex gap-2 shrink-0">
          {onEdit && (
            <Button variant="secondary" size="sm" onClick={onEdit} data-testid="ticket-detail-edit-btn">
              <Pencil className="h-3 w-3" />Edit
            </Button>
          )}
          {onClose && (
            <Button variant="ghost" size="icon" onClick={onClose} aria-label="Close ticket detail" data-testid="ticket-detail-close-btn" className="h-8 w-8">
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>
      </div>

      <div className="px-5 py-4 flex flex-col gap-5">
        {/* Status transitions */}
        {nextStatuses.length > 0 && (
          <div>
            <p className={shCls}>Status Transitions</p>
            <div data-testid="status-transition-buttons" className="flex gap-1.5 flex-wrap">
              {nextStatuses.map((next) => (
                <button key={next} type="button" onClick={() => void handleTransition(next)} disabled={transitioning !== null} data-testid={`transition-btn-${next.toLowerCase()}`}
                  className={cn(
                    "px-3.5 py-1.5 rounded-full border text-xs font-semibold transition-opacity",
                    transitioning !== null && "cursor-not-allowed opacity-60",
                    next === "DONE" ? "border-foreground/30 bg-foreground/5 text-foreground font-bold" :
                    next === "BLOCKED" ? "border-neutral-300 bg-neutral-100 text-foreground" :
                    next === "CANCELED" ? "border-neutral-200 bg-neutral-100 text-neutral-600" :
                    "border-border bg-background text-foreground",
                  )}>
                  {transitioning === next ? "…" : `→ ${TICKET_STATUS_LABELS[next]}`}
                </button>
              ))}
            </div>
            {transitionError && <span data-testid="transition-error" role="alert" className="mt-1 block text-xs text-danger">{transitionError}</span>}
          </div>
        )}

        {ticket.description && (
          <div>
            <p className={shCls}>Description</p>
            <p data-testid="ticket-detail-description" className="m-0 text-sm leading-relaxed">{ticket.description}</p>
          </div>
        )}

        <div>
          <p className={shCls}>Details</p>
          <div data-testid="ticket-detail-meta" className="flex flex-col gap-1.5">
            <div className={metaRowCls}><span className={metaLabelCls}>Priority</span><span data-testid="ticket-detail-priority">{TICKET_PRIORITY_LABELS[ticket.priority]}</span></div>
            <div className={metaRowCls}><span className={metaLabelCls}>Reporter</span><span data-testid="ticket-detail-reporter">{ticket.reporterDisplayName ?? ticket.reporterUserId}</span></div>
            <div className={metaRowCls}><span className={metaLabelCls}>Team</span><span data-testid="ticket-detail-team">{ticket.teamName ?? ticket.teamId}</span></div>
            {ticket.rcdoNodeId && <div className={metaRowCls}><span className={metaLabelCls}>RCDO</span><span data-testid="ticket-detail-rcdo">{rcdoPath ?? ticket.rcdoNodeId}</span></div>}
            {ticket.estimatePoints != null && <div className={metaRowCls}><span className={metaLabelCls}>Estimate</span><span data-testid="ticket-detail-estimate">{ticket.estimatePoints} pts</span></div>}
            {ticket.targetWeekStartDate && <div className={metaRowCls}><span className={metaLabelCls}>Target Week</span><span data-testid="ticket-detail-target-week">{ticket.targetWeekStartDate}</span></div>}
            <div className={metaRowCls}><span className={metaLabelCls}>Created</span><span>{new Date(ticket.createdAt).toLocaleString()}</span></div>
          </div>
        </div>

        <div>
          <p className={shCls}>Assignment</p>
          <div data-testid="ticket-assignment-section" className="flex gap-2 items-center flex-wrap">
            {teamMembers && teamMembers.length > 0 ? (
              <select
                value={assigneeInput}
                onChange={(e) => setAssigneeInput(e.target.value)}
                data-testid="ticket-assignee-input"
                className="h-9 rounded-default border border-border bg-surface px-3 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 min-w-[220px]"
              >
                <option value="">Unassigned</option>
                {teamMembers.map((m) => (
                  <option key={m.id} value={m.id}>{m.displayName}</option>
                ))}
              </select>
            ) : (
              <input type="text" value={assigneeInput} onChange={(e) => setAssigneeInput(e.target.value)} placeholder="User ID (leave blank to unassign)" data-testid="ticket-assignee-input"
                className="h-9 rounded-default border border-border bg-surface px-3 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 min-w-[180px]" />
            )}
            <Button variant="primary" size="sm" onClick={() => void handleAssigneeChange()} disabled={assigneeSaving} data-testid="ticket-assign-save-btn">
              {assigneeSaving ? "Saving…" : "Update"}
            </Button>
          </div>
          {assigneeError && <span data-testid="assignee-error" role="alert" className="mt-1 block text-xs text-danger">{assigneeError}</span>}
        </div>

        <div>
          <p className={shCls}>Status History</p>
          <StatusHistoryTimeline history={ticket.statusHistory} />
        </div>

        <div>
          <p className={shCls}>Linked Commits</p>
          <LinkedCommitsList commits={ticket.linkedCommits} />
        </div>
      </div>
    </div>
  );
}

/**
 * ExceptionQueueSection — filterable list of manager-review exceptions.
 */
import { useState } from "react";
import { Check, MessageSquare } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import type { ExceptionResponse, ExceptionSeverity, ExceptionType, AddCommentPayload, ResolveExceptionPayload } from "../../api/teamTypes.js";

const SEVERITY_CLS: Record<ExceptionSeverity, string> = {
  HIGH: "bg-foreground text-background",
  MEDIUM: "bg-foreground/50 text-background",
  LOW: "bg-foreground/15 text-foreground",
};
const SEVERITY_LABELS: Record<ExceptionSeverity, string> = { HIGH: "HIGH", MEDIUM: "MED", LOW: "LOW" };
const SEVERITY_ORDER: Record<ExceptionSeverity, number> = { HIGH: 0, MEDIUM: 1, LOW: 2 };
const EXCEPTION_TYPE_LABELS: Record<ExceptionType, string> = {
  MISSED_LOCK: "Missed Lock", AUTO_LOCKED: "Auto-Locked", MISSED_RECONCILE: "Missed Reconcile",
  OVER_BUDGET: "Over Budget", REPEATED_CARRY_FORWARD: "Repeated Carry-Forward",
  POST_LOCK_SCOPE_INCREASE: "Post-Lock Scope Increase", KING_CHANGED_POST_LOCK: "King Changed Post-Lock",
  HIGH_SCOPE_VOLATILITY: "High Scope Volatility",
};

type FilterMode = "all" | "unresolved" | "resolved";

export interface ExceptionQueueSectionProps {
  readonly exceptions: ExceptionResponse[];
  readonly actorUserId: string;
  readonly onResolve?: (exceptionId: string, payload: ResolveExceptionPayload) => Promise<void>;
  readonly onAddComment?: (payload: AddCommentPayload) => Promise<void>;
}

function ResolveDialog({ exception, onConfirm, onCancel }: { exception: ExceptionResponse; onConfirm: (r: string) => Promise<void>; onCancel: () => void }) {
  const [note, setNote] = useState("");
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const handleSubmit = async () => {
    if (!note.trim()) return;
    setSaving(true); setError(null);
    try { await onConfirm(note.trim()); } catch (err) { setError(err instanceof Error ? err.message : "Failed"); setSaving(false); }
  };
  return (
    <div role="dialog" aria-modal="true" aria-label="Resolve exception" data-testid="resolve-exception-dialog"
      className="fixed inset-0 z-[1100] flex items-center justify-center bg-black/35">
      <div className="w-full max-w-[420px] rounded-lg border border-border bg-surface p-6 shadow-xl flex flex-col gap-4">
        <h3 className="m-0 text-base font-semibold">Resolve Exception</h3>
        <p className="m-0 text-sm text-muted">{EXCEPTION_TYPE_LABELS[exception.exceptionType]}: {exception.description}</p>
        <div className="flex flex-col gap-1.5">
          <label htmlFor="resolution-note" className="text-xs font-semibold">
            Resolution note <span className="text-danger">*</span>
          </label>
          <textarea id="resolution-note" data-testid="resolution-note-input" value={note} onChange={(e) => setNote(e.target.value)} rows={3} placeholder="Describe how this exception was resolved…" className="w-full rounded-default border border-border bg-surface px-3 py-1.5 text-sm resize-y focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50" />
        </div>
        {error && <p role="alert" className="m-0 text-xs text-danger">{error}</p>}
        <div className="flex gap-2 justify-end">
          <Button variant="secondary" onClick={onCancel}>Cancel</Button>
          <Button variant="success" onClick={() => void handleSubmit()} disabled={!note.trim() || saving} data-testid="resolve-exception-confirm">
            {saving ? "Resolving…" : "Mark Resolved"}
          </Button>
        </div>
      </div>
    </div>
  );
}

function CommentDialog({ exception, onConfirm, onCancel }: { exception: ExceptionResponse; onConfirm: (t: string) => Promise<void>; onCancel: () => void }) {
  const [text, setText] = useState("");
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const handleSubmit = async () => {
    if (!text.trim()) return;
    setSaving(true); setError(null);
    try { await onConfirm(text.trim()); } catch (err) { setError(err instanceof Error ? err.message : "Failed"); setSaving(false); }
  };
  return (
    <div role="dialog" aria-modal="true" aria-label="Add comment" data-testid="add-comment-dialog"
      className="fixed inset-0 z-[1100] flex items-center justify-center bg-black/35">
      <div className="w-full max-w-[420px] rounded-lg border border-border bg-surface p-6 shadow-xl flex flex-col gap-4">
        <h3 className="m-0 text-base font-semibold">Add Comment</h3>
        {exception.planId && <p className="m-0 text-xs text-muted">Comment on plan: <code className="text-xs">{exception.planId}</code></p>}
        <div className="flex flex-col gap-1.5">
          <label htmlFor="comment-text" className="text-xs font-semibold">Comment <span className="text-danger">*</span></label>
          <textarea id="comment-text" data-testid="comment-text-input" value={text} onChange={(e) => setText(e.target.value)} rows={3} placeholder="Add your manager comment…" className="w-full rounded-default border border-border bg-surface px-3 py-1.5 text-sm resize-y focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50" />
        </div>
        {error && <p role="alert" className="m-0 text-xs text-danger">{error}</p>}
        <div className="flex gap-2 justify-end">
          <Button variant="secondary" onClick={onCancel}>Cancel</Button>
          <Button variant="primary" onClick={() => void handleSubmit()} disabled={!text.trim() || saving} data-testid="add-comment-confirm">
            {saving ? "Posting…" : "Post Comment"}
          </Button>
        </div>
      </div>
    </div>
  );
}

export function ExceptionQueueSection({ exceptions, actorUserId, onResolve, onAddComment }: ExceptionQueueSectionProps) {
  const [filter, setFilter] = useState<FilterMode>("unresolved");
  const [resolvingId, setResolvingId] = useState<string | null>(null);
  const [commentingId, setCommentingId] = useState<string | null>(null);

  const filtered = exceptions.filter((e) => filter === "all" ? true : filter === "unresolved" ? !e.resolved : e.resolved).slice().sort((a, b) => SEVERITY_ORDER[a.severity] - SEVERITY_ORDER[b.severity]);
  const unresolvedCount = exceptions.filter((e) => !e.resolved).length;
  const resolvingException = resolvingId ? exceptions.find((e) => e.id === resolvingId) : null;
  const commentingException = commentingId ? exceptions.find((e) => e.id === commentingId) : null;

  return (
    <section aria-labelledby="exception-queue-heading" data-testid="exception-queue-section">
      <h3 id="exception-queue-heading" className="m-0 mb-3 flex items-center gap-2 text-sm font-bold">
        Exception Queue
        {unresolvedCount > 0 && (
          <span data-testid="exception-queue-badge" className="text-[0.65rem] font-bold px-1.5 py-px rounded-full bg-foreground text-background">{unresolvedCount}</span>
        )}
      </h3>

      <div className="flex gap-1 mb-3" role="tablist" aria-label="Exception filter">
        {(["all", "unresolved", "resolved"] as FilterMode[]).map((mode) => (
          <button key={mode} type="button" role="tab" aria-selected={filter === mode} onClick={() => setFilter(mode)} data-testid={`exception-filter-${mode}`}
            className={cn("px-3.5 py-1.5 rounded-default border text-xs font-medium transition-colors", filter === mode ? "bg-foreground text-background border-foreground" : "bg-surface text-foreground border-border hover:bg-muted-bg")}>
            {mode.charAt(0).toUpperCase() + mode.slice(1)}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <p data-testid="no-exceptions-message" className={cn("text-sm", filter === "unresolved" ? "text-foreground font-semibold" : "text-muted")}>
          {filter === "unresolved" ? "✓ No open exceptions." : "No exceptions to show."}
        </p>
      ) : (
        <div data-testid="exception-list" className="rounded-default border border-border bg-surface overflow-hidden">
          {filtered.map((exception) => (
            <div key={exception.id} data-testid={`exception-item-${exception.id}`}
              className={cn("border-b border-border p-3 last:border-b-0", exception.resolved && "opacity-70")}>
              <div className="flex items-start justify-between gap-3 flex-wrap">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap mb-1.5">
                    <span data-testid={`exception-severity-${exception.id}`} className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_CLS[exception.severity])}>
                      {SEVERITY_LABELS[exception.severity]}
                    </span>
                    <span data-testid={`exception-type-${exception.id}`} className="text-xs font-semibold">{EXCEPTION_TYPE_LABELS[exception.exceptionType]}</span>
                    {exception.resolved && <Badge data-testid={`exception-resolved-badge-${exception.id}`} variant="success">Resolved</Badge>}
                  </div>
                  <p className="m-0 mb-1 text-xs">{exception.description}</p>
                  <div className="flex gap-3 text-[0.65rem] text-muted flex-wrap">
                    <span data-testid={`exception-user-${exception.id}`}>{exception.displayName ?? exception.userId}</span>
                    <span data-testid={`exception-date-${exception.id}`}>{new Date(exception.createdAt).toLocaleDateString()}</span>
                  </div>
                  {exception.resolved && exception.resolution && (
                    <div data-testid={`exception-resolution-${exception.id}`} className="mt-1.5 px-2.5 py-1.5 rounded-default bg-foreground/8 text-xs text-foreground">
                      ✓ {exception.resolution}
                    </div>
                  )}
                </div>
                {!exception.resolved && (
                  <div className="flex gap-1.5 shrink-0">
                    {onResolve && (
                      <Button variant="ghost" size="sm" onClick={() => setResolvingId(exception.id)} data-testid={`resolve-btn-${exception.id}`} className="h-7 px-2 text-xs border border-foreground/30 text-foreground hover:bg-foreground/5">
                        <Check className="h-3 w-3" />Resolve
                      </Button>
                    )}
                    {onAddComment && exception.planId && (
                      <Button variant="secondary" size="sm" onClick={() => setCommentingId(exception.id)} data-testid={`comment-btn-${exception.id}`} className="h-7 px-2 text-xs">
                        <MessageSquare className="h-3 w-3" />Comment
                      </Button>
                    )}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {resolvingException && (
        <ResolveDialog exception={resolvingException} onConfirm={async (resolution) => { await onResolve!(resolvingException.id, { resolverId: actorUserId, resolution }); setResolvingId(null); }} onCancel={() => setResolvingId(null)} />
      )}
      {commentingException && (
        <CommentDialog exception={commentingException} onConfirm={(text) => onAddComment!({ managerId: actorUserId, ...(commentingException.planId ? { planId: commentingException.planId } : {}), text })} onCancel={() => setCommentingId(null)} />
      )}
    </section>
  );
}

/**
