/** API representation of a persisted {@link ManagerReviewException}. */
public record ExceptionResponse(UUID id, UUID teamId, UUID planId, UUID userId,
		/** Human-readable display name of the user associated with this exception. */
		String displayName,
		ExceptionType exceptionType,
		ExceptionSeverity severity, String description, LocalDate weekStartDate, boolean resolved, String resolution,
		Instant resolvedAt, UUID resolvedById, Instant createdAt) {

	/** Convenience factory without a display name (displayName will be null). */
	public static ExceptionResponse from(ManagerReviewException e) {
		return from(e, null);
	}

	/** Factory that includes the resolved display name for the user. */
	public static ExceptionResponse from(ManagerReviewException e, String displayName) {
		return new ExceptionResponse(e.getId(), e.getTeamId(), e.getPlanId(), e.getUserId(), displayName,
				e.getExceptionType(), e.getSeverity(), e.getDescription(), e.getWeekStartDate(), e.isResolved(),
				e.getResolution(), e.getResolvedAt(), e.getResolvedById(), e.getCreatedAt());
	}
}

/**
 * InsightPanel — displays AI-generated insight cards for a team week
 * (mode='team') or a personal plan (mode='personal').
 *
 * Uses balanced text layout: each card's paragraph is shrinkwrapped to
 * the tightest width that doesn't add extra lines, so line lengths are
 * roughly equal instead of ragged-right. See lib/useBalancedText.ts.
 */
import { useMemo } from "react";
import { Bot } from "lucide-react";
import { Badge } from "../ui/Badge.js";
import { Skeleton } from "../ui/Skeleton.js";
import { cn } from "../../lib/utils.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useTeamInsights, usePlanInsights } from "../../api/ragHooks.js";
import { useBalancedText } from "../../lib/useBalancedText.js";
import type { InsightCard } from "../../api/ragApi.js";

// ── Balanced text config ──────────────────────────────────────────────────────
// Must be a named font (not system-ui) for accurate canvas measurement.
// Matches the `text-sm` class on the insight text <p> (14px Inter).
const INSIGHT_FONT = '14px "Inter", sans-serif';

// ── Severity helpers ──────────────────────────────────────────────────────────

type SeverityLevel = "HIGH" | "MEDIUM" | "LOW";

function severityBadgeVariant(
  severity: string,
): "danger" | "warning" | "primary" | "default" {
  switch (severity.toUpperCase() as SeverityLevel) {
    case "HIGH":
      return "danger";
    case "MEDIUM":
      return "warning";
    case "LOW":
      return "primary";
    default:
      return "default";
  }
}

function severityLabel(severity: string): string {
  return severity.charAt(0).toUpperCase() + severity.slice(1).toLowerCase();
}

// ── Individual card ───────────────────────────────────────────────────────────

function InsightCardItem({
  card,
  balancedWidth,
}: {
  card: InsightCard;
  balancedWidth: number | undefined;
}) {
  return (
    <div
      className={cn(
        "rounded-default border border-border bg-surface px-4 py-3 flex flex-col gap-2",
      )}
      data-testid={`insight-card-${card.suggestionId}`}
    >
      {/* Header row: severity + feedback buttons */}
      <div className="flex items-center justify-between gap-2">
        <Badge
          variant={severityBadgeVariant(card.severity)}
          className="text-[0.65rem] capitalize"
          data-testid={`insight-severity-${card.suggestionId}`}
        >
          {severityLabel(card.severity)}
        </Badge>
        <AiFeedbackButtons suggestionId={card.suggestionId} />
      </div>

      {/* Insight text — balanced via Pretext shrinkwrap measurement */}
      <p
        className="m-0 text-sm text-foreground leading-relaxed"
        style={balancedWidth != null ? { maxWidth: balancedWidth } : undefined}
        data-testid={`insight-text-${card.suggestionId}`}
      >
        {card.insightText}
      </p>

      {/* Action suggestion */}
      {card.actionSuggestion && (
        <p
          className="m-0 text-xs text-muted italic"
          data-testid={`insight-action-${card.suggestionId}`}
        >
          → {card.actionSuggestion}
        </p>
      )}

      {/* Source entity IDs are internal UUIDs — not surfaced to the user */}
    </div>
  );
}

// ── Skeleton loading cards ────────────────────────────────────────────────────

function InsightSkeletons() {
  return (
    <div
      className="flex flex-col gap-3"
      data-testid="insight-panel-loading"
      aria-busy="true"
    >
      {[0, 1, 2].map((i) => (
        <div
          key={i}
          className="rounded-default border border-border px-4 py-3 flex flex-col gap-2"
        >
          <Skeleton className="h-4 w-16" />
          <Skeleton className="h-3.5 w-full" />
          <Skeleton className="h-3.5 w-4/5" />
          <Skeleton className="h-3 w-2/3" />
        </div>
      ))}
    </div>
  );
}

// ── Balanced insight card list ─────────────────────────────────────────────────

/**
 * Renders a list of insight cards with Pretext-balanced text.
 * The `ref` from `useBalancedText` is attached to the container so it
 * re-measures when the panel resizes (e.g. sidebar toggle, window resize).
 */
function BalancedInsightCardList({ insights }: { insights: InsightCard[] }) {
  const insightTexts = useMemo(
    () => insights.map((c) => c.insightText),
    [insights],
  );

  const { ref, widths } = useBalancedText(insightTexts, INSIGHT_FONT);

  return (
    <div ref={ref} className="flex flex-col gap-3">
      {insights.map((card) => (
        <InsightCardItem
          key={card.suggestionId}
          card={card}
          balancedWidth={widths.get(card.insightText)}
        />
      ))}
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────

interface InsightPanelTeamProps {
  mode: "team";
  teamId?: string;
  weekStart?: string;
  planId?: never;
}

interface InsightPanelPersonalProps {
  mode: "personal";
  planId?: string;
  teamId?: never;
  weekStart?: never;
}

type InsightPanelProps = InsightPanelTeamProps | InsightPanelPersonalProps;

function TeamInsightPanel({
  teamId,
  weekStart,
}: {
  teamId?: string;
  weekStart?: string;
}) {
  const { data, loading, error } = useTeamInsights(
    teamId ?? null,
    weekStart ?? "",
  );

  if (loading) return <InsightSkeletons />;

  if (error) {
    return (
      <p
        className="text-sm text-danger"
        data-testid="insight-panel-error"
      >
        Failed to load insights: {error.message}
      </p>
    );
  }

  if (!data?.aiAvailable) {
    return (
      <div
        className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic"
        data-testid="insight-panel-unavailable"
      >
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI insights are currently unavailable.
      </div>
    );
  }

  if (data.insights.length === 0) {
    return (
      <p
        className="text-sm text-muted"
        data-testid="insight-panel-empty"
      >
        No AI insights available for this period.
      </p>
    );
  }

  return <BalancedInsightCardList insights={data.insights} />;
}

function PersonalInsightPanel({ planId }: { planId?: string }) {
  const { data, loading, error } = usePlanInsights(planId ?? null);

  if (loading) return <InsightSkeletons />;

  if (error) {
    return (
      <p
        className="text-sm text-danger"
        data-testid="insight-panel-error"
      >
        Failed to load insights: {error.message}
      </p>
    );
  }

  if (!data?.aiAvailable) {
    // Silently hide when AI not available — avoids noise in consolidated sections
    return null;
  }

  if (data.insights.length === 0) {
    // Return null when empty — parent section handles the "nothing here" state
    return null;
  }

  return <BalancedInsightCardList insights={data.insights} />;
}

/**
 * InsightPanel renders AI-generated insight cards with balanced text layout.
 *
 * Uses canvas-based text measurement (lib/useBalancedText.ts) to compute a
 * shrinkwrapped max-width that distributes words evenly across lines,
 * eliminating the short trailing "orphan" line typical of ragged-right text.
 *
 * Set `mode="team"` with `teamId` + `weekStart` for team-level insights, or
 * `mode="personal"` with `planId` for plan-level personal insights.
 */
export function InsightPanel(props: InsightPanelProps) {
  return (
    <div data-testid="insight-panel">
      {props.mode === "team" ? (
        <TeamInsightPanel
          {...(props.teamId !== undefined && { teamId: props.teamId })}
          {...(props.weekStart !== undefined && { weekStart: props.weekStart })}
        />
      ) : (
        <PersonalInsightPanel
          {...(props.planId !== undefined && { planId: props.planId })}
        />
      )}
    </div>
  );
}

